将最外层i循环和中间层j循环交换，然后对j和k循环进行分块。

// 分块大小
#define TILE_J 64
#define TILE_K 64

for (int jj = 0; jj < _PB_N; jj += TILE_J)
  for (int kk = 0; kk < _PB_M; kk += TILE_K)
    for (int i = 0; i < _PB_M; i++)
      for (int j = jj; j < min(jj+TILE_J, _PB_N); j++)
        for (int k = max(i+1, kk); k < min(_PB_M, kk+TILE_K); k++)
          B[i][j] += A[k][i] * B[k][j];

for (int i = 0; i < _PB_M; i++)
  for (int j = 0; j < _PB_N; j++)
    B[i][j] = alpha * B[i][j];

1) 将A矩阵转置存储为A_T[i][k] = A[k][i]，使访问变为连续；
2) 添加显式预取指令；
3) 使用临时变量累积结果，减少对B[i][j]的重复写入。

// 转置A矩阵
DATA_TYPE POLYBENCH_2D(A_T,M,M,m,m);
for (int i = 0; i < m; i++)
  for (int k = i+1; k < m; k++)
    A_T[i][k] = A[k][i];

// 优化后的内核
for (int i = 0; i < _PB_M; i++) {
  for (int j = 0; j < _PB_N; j++) {
    DATA_TYPE temp = B[i][j];
    for (int k = i+1; k < _PB_M; k++) {
      // 预取A_T[i][k+4]和B[k+4][j]
      __builtin_prefetch(&A_T[i][k+4], 0, 3);
      __builtin_prefetch(&B[k+4][j], 0, 3);
      temp += A_T[i][k] * B[k][j];
    }
    B[i][j] = alpha * temp;
  }
}

对j循环进行向量化处理，利用AVX2或AVX-512指令集。

#include <immintrin.h>

for (int i = 0; i < _PB_M; i++) {
  for (int j = 0; j < _PB_N; j += 8) { // 假设使用AVX2，处理8个float
    __m256 b_vec = _mm256_loadu_ps(&B[i][j]);
    for (int k = i+1; k < _PB_M; k++) {
      __m256 a_vec = _mm256_set1_ps(A[k][i]);
      __m256 b_k_vec = _mm256_loadu_ps(&B[k][j]);
      b_vec = _mm256_fmadd_ps(a_vec, b_k_vec, b_vec);
    }
    __m256 alpha_vec = _mm256_set1_ps(alpha);
    b_vec = _mm256_mul_ps(alpha_vec, b_vec);
    _mm256_storeu_ps(&B[i][j], b_vec);
  }
  // 处理剩余元素
}
